pseudocode:
```
export async function getCase(caseId) {
  const supabase = await createClient()  // @/lib/supabase/server
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return null
  const { data } = await supabase.from('cases').select('*').eq('id', caseId).eq('user_id', user.id).single()
  return data ?? null
}

export async function getCaseInputs(caseId) {
  const supabase = await createClient()
  const { data } = await supabase.from('case_inputs').select('*').eq('case_id', caseId).order('display_order')
  return data ?? []
}

export async function getCurrentResult(caseId) {
  const supabase = await createClient()
  const { data: caseRow } = await supabase.from('cases').select('current_result_id').eq('id', caseId).single()
  if (!caseRow?.current_result_id) return null
  const { data } = await supabase.from('case_results').select('*').eq('id', caseRow.current_result_id).single()
  return data ?? null
}

export async function listRecentCases(limit = 50) {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return []
  const { data } = await supabase.from('cases').select('*').eq('user_id', user.id).order('created_at', { ascending: false }).limit(limit)
  return data ?? []
}
```

