export async function addCaseInput(caseId, rawText, timeTag, timeOffsetMinutes) {
  const supabase = await createClient()
  const user = await getAuthUser(supabase)  // 내부 헬퍼
  // display_order 계산: 현재 최대값 + 1
  const { count } = await supabase.from('case_inputs').select('*', { count: 'exact', head: true }).eq('case_id', caseId)
  const displayOrder = (count ?? 0) + 1
  const { data, error } = await supabase.from('case_inputs').insert({ case_id: caseId, raw_text: rawText, time_tag: timeTag, time_offset_minutes: timeOffsetMinutes, display_order: displayOrder }).select().single()
  if (error) throw new Error(error.message)
  revalidatePath(`/cases/new`)  // 필요시
  return data
}
```

