export async function generateHpi(structuredCase, rawInputs, cc) {
  hpiInputs = structuredCase.inputs.filter(i => i.sections.includes('hpi'))

  corrections = await loadCorrections(cc, 'hpi')  // 최신 5개
  styleRules = await loadStyleRules(cc, 'hpi')

  // system prompt에 규칙 append
  systemPrompt = GENERATE_HPI_SYSTEM_PROMPT
  if (styleRules.length > 0) {
    systemPrompt += '\n\n## Additional Rules (follow strictly):\n' + styleRules.map(r => '- ' + r).join('\n')
  }

  userPrompt = JSON.stringify({
    hpiInputs,
    ccSpecificFields: { ... },
    rawInputs,
    ...(corrections.length > 0 ? { correctionExamples: corrections } : {})
  })

  return generateText(userPrompt, systemPrompt)
}
```

